async function execute(browser, params) {
    const product = await browser.extractComponent(
        {
            typeName: 'ProductDetailsHero',
            schema: '{ name: string; physicalLocationInStore?: string; aisle?: string; }'
        },
        params.productName
    );
    if (!product) {
        throw new Error('Could not find product details for: ' + params.productName);
    }
    const location = product.physicalLocationInStore || product.aisle;
    if (!location) {
        return { success: false, message: 'Store location not available for ' + params.productName };
    }
    return { success: true, message: params.productName + ' is located at: ' + location, data: { location } };
}
